141: func (mg *Migrator) AddMigration(id string, m Migration) {
142: 	if _, ok := mg.migrationIds[id]; ok {
143: 		panic(fmt.Sprintf("migration id conflict: %s", id))
144: 	}
145: 
146: 	m.SetId(id)
147: 	mg.migrations = append(mg.migrations, m)
148: 	mg.migrationIds[id] = struct{}{}
