151: func (mg *Migrator) GetMigrationIDs(excludeNotLogged bool) []string {
152: 	result := make([]string, 0, len(mg.migrations))
153: 	for _, migration := range mg.migrations {
154: 		if migration.SkipMigrationLog() && excludeNotLogged {
155: 			continue
156: 		}
157: 		result = append(result, migration.Id())
158: 	}
159: 	return result
160: }
