57: func (db *MySQLDialect) SQLType(c *Column) string {
58: 	var res string
59: 	switch c.Type {
60: 	case DB_Bool:
61: 		res = DB_TinyInt
62: 		c.Length = 1
63: 	case DB_Serial:
64: 		c.IsAutoIncrement = true
65: 		c.IsPrimaryKey = true
66: 		c.Nullable = false
67: 		res = DB_Int
68: 	case DB_BigSerial:
69: 		c.IsAutoIncrement = true
70: 		c.IsPrimaryKey = true
71: 		c.Nullable = false
72: 		res = DB_BigInt
73: 	case DB_Bytea:
74: 		res = DB_Blob
75: 	case DB_TimeStampz:
76: 		res = DB_Char
77: 		c.Length = 64
78: 	case DB_NVarchar:
79: 		res = DB_Varchar
80: 	case DB_Uuid:
81: 		res = DB_Char
82: 		c.Length = 36
83: 	default:
84: 		res = c.Type
85: 	}
86: 
87: 	var hasLen1 = (c.Length > 0)
88: 	var hasLen2 = (c.Length2 > 0)
89: 
90: 	if res == DB_BigInt && !hasLen1 && !hasLen2 {
91: 		c.Length = 20
92: 		hasLen1 = true
93: 	}
94: 
95: 	if hasLen2 {
96: 		res += "(" + strconv.Itoa(c.Length) + "," + strconv.Itoa(c.Length2) + ")"
97: 	} else if hasLen1 {
98: 		res += "(" + strconv.Itoa(c.Length) + ")"
99: 	}
100: 
101: 	switch c.Type {
102: 	case DB_Char, DB_Varchar, DB_NVarchar, DB_TinyText, DB_Text, DB_MediumText, DB_LongText:
103: 		if c.IsLatin {
104: 			res += " CHARACTER SET latin1 COLLATE latin1_bin"
105: 		} else {
106: 			res += " CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci"
107: 		}
108: 	}
109: 
110: 	return res
111: }
