145: func (db *MySQLDialect) CleanDB(engine *xorm.Engine) error {
146: 	tables, err := engine.DBMetas()
147: 	if err != nil {
148: 		return err
149: 	}
150: 	sess := engine.NewSession()
151: 	defer sess.Close()
152: 
153: 	for _, table := range tables {
154: 		switch table.Name {
155: 		default:
156: 			if _, err := sess.Exec("set foreign_key_checks = 0"); err != nil {
157: 				return fmt.Errorf("%v: %w", "failed to disable foreign key checks", err)
158: 			}
159: 			if _, err := sess.Exec("drop table " + table.Name + " ;"); err != nil {
160: 				return fmt.Errorf("failed to delete table %q: %w", table.Name, err)
161: 			}
162: 			if _, err := sess.Exec("set foreign_key_checks = 1"); err != nil {
163: 				return fmt.Errorf("%v: %w", "failed to disable foreign key checks", err)
164: 			}
165: 		}
166: 	}
167: 
168: 	return nil
169: }
