171: // TruncateDBTables truncates all the tables.
172: // A special case is the dashboard_acl table where we keep the default permissions.
173: func (db *MySQLDialect) TruncateDBTables(engine *xorm.Engine) error {
174: 	tables, err := engine.Dialect().GetTables()
175: 	if err != nil {
176: 		return err
177: 	}
178: 	sess := engine.NewSession()
179: 	defer sess.Close()
180: 
181: 	for _, table := range tables {
182: 		switch table.Name {
183: 		case "migration_log":
184: 			continue
185: 		case "dashboard_acl":
186: 			// keep default dashboard permissions
187: 			if _, err := sess.Exec(fmt.Sprintf("DELETE FROM %v WHERE dashboard_id != -1 AND org_id != -1;", db.Quote(table.Name))); err != nil {
188: 				return fmt.Errorf("failed to truncate table %q: %w", table.Name, err)
189: 			}
190: 			if _, err := sess.Exec(fmt.Sprintf("ALTER TABLE %v AUTO_INCREMENT = 3;", db.Quote(table.Name))); err != nil {
191: 				return fmt.Errorf("failed to reset table %q: %w", table.Name, err)
192: 			}
193: 		default:
194: 			if _, err := sess.Exec(fmt.Sprintf("TRUNCATE TABLE %v;", db.Quote(table.Name))); err != nil {
195: 				return fmt.Errorf("failed to truncate table %q: %w", table.Name, err)
196: 			}
197: 		}
198: 	}
199: 
200: 	return nil
201: }
