61: func (db *PostgresDialect) SQLType(c *Column) string {
62: 	var res string
63: 	switch t := c.Type; t {
64: 	case DB_TinyInt:
65: 		res = DB_SmallInt
66: 		return res
67: 	case DB_MediumInt, DB_Int, DB_Integer:
68: 		if c.IsAutoIncrement {
69: 			return DB_Serial
70: 		}
71: 		return DB_Integer
72: 	case DB_Serial, DB_BigSerial:
73: 		c.IsAutoIncrement = true
74: 		c.Nullable = false
75: 		res = t
76: 	case DB_Binary, DB_VarBinary:
77: 		return DB_Bytea
78: 	case DB_DateTime:
79: 		res = DB_TimeStamp
80: 	case DB_TimeStampz:
81: 		return "timestamp with time zone"
82: 	case DB_Float:
83: 		res = DB_Real
84: 	case DB_TinyText, DB_MediumText, DB_LongText:
85: 		res = DB_Text
86: 	case DB_NVarchar:
87: 		res = DB_Varchar
88: 	case DB_Uuid:
89: 		return DB_Uuid // do not add the length options
90: 	case DB_Blob, DB_TinyBlob, DB_MediumBlob, DB_LongBlob:
91: 		return DB_Bytea
92: 	case DB_Double:
93: 		return "DOUBLE PRECISION"
94: 	default:
95: 		if c.IsAutoIncrement {
96: 			return DB_Serial
97: 		}
98: 		res = t
99: 	}
100: 
101: 	var hasLen1 = (c.Length > 0)
102: 	var hasLen2 = (c.Length2 > 0)
103: 	if hasLen2 {
104: 		res += "(" + strconv.Itoa(c.Length) + "," + strconv.Itoa(c.Length2) + ")"
105: 	} else if hasLen1 {
106: 		res += "(" + strconv.Itoa(c.Length) + ")"
107: 	}
108: 	return res
109: }
