152: 	if err != nil {
153: 		return err
154: 	}
155: 	sess := engine.NewSession()
156: 	defer sess.Close()
157: 
158: 	for _, table := range tables {
159: 		switch table.Name {
160: 		case "":
161: 			continue
162: 		case "migration_log":
163: 			continue
164: 		case "dashboard_acl":
165: 			// keep default dashboard permissions
166: 			if _, err := sess.Exec(fmt.Sprintf("DELETE FROM %v WHERE dashboard_id != -1 AND org_id != -1;", db.Quote(table.Name))); err != nil {
167: 				return fmt.Errorf("failed to truncate table %q: %w", table.Name, err)
168: 			}
169: 			if _, err := sess.Exec(fmt.Sprintf("ALTER SEQUENCE %v RESTART WITH 3;", db.Quote(fmt.Sprintf("%v_id_seq", table.Name)))); err != nil {
170: 				return fmt.Errorf("failed to reset table %q: %w", table.Name, err)
171: 			}
172: 		default:
173: 			if _, err := sess.Exec(fmt.Sprintf("TRUNCATE TABLE %v RESTART IDENTITY CASCADE;", db.Quote(table.Name))); err != nil {
174: 				if db.isUndefinedTable(err) {
175: 					continue
176: 				}
177: 				return fmt.Errorf("failed to truncate table %q: %w", table.Name, err)
178: 			}
179: 		}
180: 	}
181: 
182: 	return nil
183: }
