297: func (db *PostgresDialect) Lock(cfg LockCfg) error {
298: 	// trying to obtain the lock for a resource identified by a 64-bit or 32-bit key value
299: 	// the lock is exclusive: multiple lock requests stack, so that if the same resource is locked three times
300: 	// it must then be unlocked three times to be released for other sessions' use.
301: 	// it will either obtain the lock immediately and return true,
302: 	// or return false if the lock cannot be acquired immediately.
303: 	query := "SELECT pg_try_advisory_lock(?)"
304: 	var success bool
305: 
306: 	_, err := cfg.Session.SQL(query, cfg.Key).Get(&success)
307: 	if err != nil {
308: 		return err
309: 	}
310: 	if !success {
311: 		return ErrLockDB
312: 	}
313: 
314: 	return nil
315: }
