90: func (db *SQLite3) ColumnCheckSQL(tableName, columnName string) (string, []any) {
91: 	// Use PRAGMA table_info to check if a column exists on a table. In SQLite, quoting with backticks inside
92: 	// pragma_table_info(<expr>) can be interpreted as an identifier/column. Instead, pass the table name as a
93: 	// string literal to avoid ambiguity. We cannot parameterize identifiers, but pragma_table_info accepts string
94: 	// literals, so we embed a single-quoted literal safely by replacing single quotes if any.
